import{_ as t,o as n,c as a,a2 as o}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"Automated SEO Content Pipeline","description":"Proof-of-work blog publishing from merged PRs using n8n and Cloudflare Pages.","frontmatter":{"title":"Automated SEO Content Pipeline","description":"Proof-of-work blog publishing from merged PRs using n8n and Cloudflare Pages."},"headers":[],"relativePath":"best-practices/seo-pipeline.md","filePath":"best-practices/seo-pipeline.md"}'),s={name:"best-practices/seo-pipeline.md"};function i(r,e,l,d,c,p){return n(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="automated-seo-content-pipeline" tabindex="-1">Automated SEO Content Pipeline <a class="header-anchor" href="#automated-seo-content-pipeline" aria-label="Permalink to &quot;Automated SEO Content Pipeline&quot;">​</a></h1><blockquote><p><strong>Pattern:</strong> This page follows the normalized best-practice shape for workflow documentation: fast summary first, then implementation details, verification, and adjacent references.</p></blockquote><p>OpenSIN AI Agent&#39;s SEO pipeline turns real merged pull requests into blog-ready Markdown, so publishing stays tied to actual shipped work instead of generic AI filler.</p><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>Standard</th></tr></thead><tbody><tr><td>Trigger</td><td>Merged PR or webhook payload into n8n</td></tr><tr><td>Orchestrator</td><td>Self-hosted n8n workflow on OCI</td></tr><tr><td>Output</td><td>Markdown committed to <code>OpenSIN-AI/Biz-SIN-Blog-Posts</code> and deployed via Cloudflare Pages</td></tr><tr><td>Proof</td><td>Successful execution history, generated Markdown, and downstream deploy confirmation</td></tr></tbody></table><h2 id="_1-pipeline-flow" tabindex="-1">1. Pipeline flow <a class="header-anchor" href="#_1-pipeline-flow" aria-label="Permalink to &quot;1. Pipeline flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐   webhook   ┌─────────────────────┐</span></span>
<span class="line"><span>│  GitHub Repo    │────────────▶│  n8n (OCI VM)       │</span></span>
<span class="line"><span>│  (any OpenSIN)  │             │  Workflow sq7YR8... │</span></span>
<span class="line"><span>└─────────────────┘             └─────────┬───────────┘</span></span>
<span class="line"><span>                                            │</span></span>
<span class="line"><span>                                  ┌─────────▼──────────┐</span></span>
<span class="line"><span>                                  │  Function Nodes    │</span></span>
<span class="line"><span>                                  │  - Generate Draft  │</span></span>
<span class="line"><span>                                  │  - Humanize + b64  │</span></span>
<span class="line"><span>                                  │  - Commit (HTTPS)  │</span></span>
<span class="line"><span>                                  └─────────┬──────────┘</span></span>
<span class="line"><span>                                            │</span></span>
<span class="line"><span>                                  ┌─────────▼──────────┐</span></span>
<span class="line"><span>                                  │  GitHub API (PUT)  │</span></span>
<span class="line"><span>                                  │  OpenSIN-AI/       │</span></span>
<span class="line"><span>                                  │  Biz-SIN-Blog-Posts│</span></span>
<span class="line"><span>                                  └─────────┬──────────┘</span></span>
<span class="line"><span>                                            │</span></span>
<span class="line"><span>                                  ┌─────────▼──────────┐</span></span>
<span class="line"><span>                                  │ Cloudflare Pages   │</span></span>
<span class="line"><span>                                  │ blog.opensin.ai    │</span></span>
<span class="line"><span>                                  └────────────────────┘</span></span></code></pre></div><h2 id="_2-why-function-nodes-instead-of-the-http-request-node" tabindex="-1">2. Why function nodes instead of the HTTP Request node <a class="header-anchor" href="#_2-why-function-nodes-instead-of-the-http-request-node" aria-label="Permalink to &quot;2. Why function nodes instead of the HTTP Request node&quot;">​</a></h2><p>Initial attempts with the built-in HTTP Request node created too many edge cases for a content pipeline that needs deterministic output.</p><table tabindex="0"><thead><tr><th>Problem</th><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>JSON body encoding</td><td>GitHub received malformed JSON</td><td>Switch to a raw body expression using the workflow&#39;s double-curly <code>JSON.stringify(...)</code> template syntax</td></tr><tr><td>Content-Type conflicts</td><td>Node sent form-urlencoded data</td><td>Set <code>contentType: raw</code> and <code>sendBody: true</code></td></tr><tr><td>Base64 handling</td><td>Needed to embed <code>$json.content_base64</code> cleanly</td><td>Use direct expression interpolation inside the raw payload</td></tr><tr><td>Reliability</td><td>Node-level edge cases made debugging slow</td><td>Replace the HTTP node with a Function node using <code>https</code> for full control</td></tr></tbody></table><h2 id="_3-determinism-and-safety" tabindex="-1">3. Determinism and safety <a class="header-anchor" href="#_3-determinism-and-safety" aria-label="Permalink to &quot;3. Determinism and safety&quot;">​</a></h2><ul><li>Generation runs synchronously inside Function nodes.</li><li>External network activity is limited to the final HTTPS commit and deploy path.</li><li>Given the same PR payload, the Markdown output should stay stable.</li><li>This avoids unnecessary rate-limit, token-rotation, and phrasing drift problems in the publishing step.</li></ul><h2 id="_4-configuration-reference" tabindex="-1">4. Configuration reference <a class="header-anchor" href="#_4-configuration-reference" aria-label="Permalink to &quot;4. Configuration reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Value (Placeholder)</th></tr></thead><tbody><tr><td><strong>n8n API Key</strong></td><td><code>YOUR_N8N_API_KEY</code> placeholder</td></tr><tr><td><strong>n8n Host</strong></td><td>Internal self-hosted n8n endpoint (see owning infra repo)</td></tr><tr><td><strong>Workflow ID</strong></td><td><code>sq7YR8vkdPf3usnz</code></td></tr><tr><td><strong>GitHub Token</strong></td><td><code>YOUR_GITHUB_TOKEN</code> placeholder (repo scope) — store in n8n Credentials</td></tr><tr><td><strong>Blog Repo</strong></td><td><code>OpenSIN-AI/Biz-SIN-Blog-Posts</code></td></tr><tr><td><strong>Cloudflare Pages</strong></td><td>Project <code>opensin-blog</code> → Domain <code>blog.opensin.ai</code></td></tr><tr><td><strong>Trigger Path</strong></td><td><code>/webhook/blog-publish</code> (POST)</td></tr></tbody></table><h2 id="_5-verification-checklist" tabindex="-1">5. Verification checklist <a class="header-anchor" href="#_5-verification-checklist" aria-label="Permalink to &quot;5. Verification checklist&quot;">​</a></h2><ul><li>[ ] The workflow execution history shows a successful run for the expected PR payload</li><li>[ ] Generated Markdown matches the merged PR content and structure</li><li>[ ] The blog repository received the committed file update</li><li>[ ] Cloudflare Pages picked up the deploy or shows a healthy downstream state</li><li>[ ] Failure output is inspectable when the workflow does not complete</li></ul><h2 id="_6-monitoring-and-backlog" tabindex="-1">6. Monitoring and backlog <a class="header-anchor" href="#_6-monitoring-and-backlog" aria-label="Permalink to &quot;6. Monitoring and backlog&quot;">​</a></h2><h3 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h3><ul><li><strong>Execution history:</strong> inspect <code>/api/v1/executions?workflowId=sq7YR8vkdPf3usnz</code></li><li><strong>Suggested alerts:</strong> workflow failure, no success in 24h, or blog repo inactivity</li></ul><h3 id="backlog" tabindex="-1">Backlog <a class="header-anchor" href="#backlog" aria-label="Permalink to &quot;Backlog&quot;">​</a></h3><ul><li>[ ] Idempotent updates via SHA lookup</li><li>[ ] Dynamic PR number in filename and message</li><li>[ ] Configurable post template stored in Google Docs or Markdown</li><li>[ ] Enriched content with code snippets, changed files, and commit SHAs</li><li>[ ] Tag inference from file paths</li><li>[ ] Scheduled publishing windows</li><li>[ ] CI test coverage for Function nodes</li><li>[ ] Token placement in the n8n credential store</li><li>[ ] Webhook secret enforcement</li></ul><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="/best-practices/page-pattern.html">Best-Practice Page Pattern</a></li><li><a href="/best-practices/ci-cd-n8n.html">CI/CD mit n8n + sin-github-action</a></li><li><code>docs/seo-pipeline.md</code> for the high-level overview</li><li><code>n8n-workflows/auto-blog-publisher.json</code> for the workflow template</li><li><a href="https://docs.github.com/en/rest/repos/contents#create-or-update-file-contents" target="_blank" rel="noreferrer">GitHub API – Create or update file contents</a></li><li><a href="https://developers.cloudflare.com/pages/" target="_blank" rel="noreferrer">Cloudflare Pages – Deploy from Git</a></li></ul><hr><p><em>Last updated:</em> 2026-04-21<br><em>Status:</em> <strong>ACTIVE</strong><br><em>Maintainer:</em> sin-zeus<br><em>Review cycle:</em> Monthly or after any workflow change</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>n8n CI/CD</strong></td><td>0.0</td><td>Self-hosted auf OCI VM</td></tr><tr><td><strong>Box.com Storage</strong></td><td>0.0</td><td>Artefakte zu Box.com</td></tr></tbody></table>`,28)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
